 78	        props: { className: tableColumnClasses[3] },
 79	      },
 80	      {
 81	        id: 'avgDuration',
 82	        title: t('Average duration'),
 83	        sort: (summary, direction: 'asc' | 'desc') =>
 84	          sortTimeStrings(summary, 'avg_duration', direction),
