 99	        sort: (summary, direction: 'asc' | 'desc') =>
100	          sortByNumbers(summary, 'succeeded', direction),
101	        transforms: [sortable],
102	        props: {
103	          className: tableColumnClasses[5],
104	          info: {
105	            tooltip: t(
106	              'Success rate measure the % of successfully completed pipeline runs in relation to the total number of pipeline runs',
107	            ),
108	            className: 'pipeline-overview__for-pipelines-list__tooltip',
109	          },
110	        },
111	      },
112	    ];
113	    if (!hideLastRunTime) {
114	      columns.push({
115	        id: 'lastRunTime',
116	        title: t('Last run time'),
117	        sort: (summary, direction: 'asc' | 'desc') =>
118	          sortByTimestamp(summary, 'last_runtime', direction),
119	        transforms: [sortable],
120	        props: { className: tableColumnClasses[6] },
121	      });
122	    }
123	
124	    return columns;
125	  }, [t, hideLastRunTime]);
126	
127	  const [columns] = useActiveColumns({
128	    columns: plrColumns,
129	    showNamespaceOverride: false,
130	    columnManagementID: '',
131	  });
132	
133	  const isEmptyData =
134	    (!summaryDataFiltered || summaryDataFiltered.length === 0) &&
135	    (!summaryData || summaryData.length === 0);
136	
137	  if (loaded && isEmptyData) {
138	    return <EmptyMsg />;
139	  }
140	  return (
141	    <VirtualizedTable
142	      columns={columns}
143	      Row={PipelineRunsForPipelinesRowK8s}
144	      data={summaryDataFiltered || summaryData}
145	      loaded={loaded}
146	      loadError={false}
147	      unfilteredData={summaryData}
148	      EmptyMsg={EmptyMsg}
149	      rowData={{ hideLastRunTime, projects, projectsLoaded }}
150	    />
151	  );
152	};
153	
154	export default PipelineRunsForPipelinesListK8s;

